function Presence() {
  const [people, setPeople] = React.useState([
    { name: 'Alice', home: true, since: '8:00 AM', avatar: 'A', color: '#ef4444' },
    { name: 'Bob', home: false, since: '7:30 AM', avatar: 'B', color: '#3b82f6' },
    { name: 'Charlie', home: true, since: '9:15 AM', avatar: 'C', color: '#10b981' },
    { name: 'Diana', home: false, since: '6:00 AM', avatar: 'D', color: '#8b5cf6' }
  ]);

  return (
    <div style={{ fontFamily: 'system-ui', background: '#111827', color: '#f3f4f6', width: '100%', height: '100%', padding: 16, borderRadius: 8, boxSizing: 'border-box', display: 'flex', flexDirection: 'column' }}>
      <div style={{ fontSize: 14, fontWeight: 600, marginBottom: 12, color: '#9ca3af' }}>Who's Home</div>
      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 12, flex: 1 }}>
        {people.map((p, i) => (
          <div key={i} style={{ background: '#1f2937', borderRadius: 10, padding: 14, display: 'flex', flexDirection: 'column', alignItems: 'center', gap: 8, border: p.home ? '2px solid #10b981' : '2px solid transparent' }}>
            <div style={{ width: 44, height: 44, borderRadius: '50%', background: p.color, display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 18, fontWeight: 700, color: '#fff' }}>{p.avatar}</div>
            <div style={{ fontSize: 14, fontWeight: 600 }}>{p.name}</div>
            <div style={{ fontSize: 11, color: p.home ? '#10b981' : '#6b7280', fontWeight: 600 }}>{p.home ? 'Home' : 'Away'}</div>
            <div style={{ fontSize: 10, color: '#475569' }}>Since {p.since}</div>
          </div>
        ))}
      </div>
    </div>
  );
}
render(<Presence/>);
